  --font-display: "NCLRekron", "Orbitron", sans-serif;
  --radius: .25rem;

  --shadow-2xs: 0px 1px 2px 0px rgba(0, 0, 0, 0.05);
  --shadow-xs: 0px 1px 3px 0px rgba(0, 0, 0, 0.08);
  --shadow-sm: 0px 2px 4px -1px rgba(0, 0, 0, 0.06);
  --shadow: 0px 4px 6px -1px rgba(0, 0, 0, 0.08);
  --shadow-md: 0px 6px 10px -2px rgba(0, 0, 0, 0.10);
  --shadow-lg: 0px 10px 15px -3px rgba(0, 0, 0, 0.12);
  --shadow-xl: 0px 20px 25px -5px rgba(0, 0, 0, 0.15);
  --shadow-2xl: 0px 25px 50px -12px rgba(0, 0, 0, 0.25);
}

.dark {
  --button-outline: rgba(255,255,255, .10);
  --badge-outline: rgba(255,255,255, .05);
  --opaque-button-border-intensity: 9;
  --elevate-1: rgba(255,255,255, .04);
  --elevate-2: rgba(255,255,255, .09);

  --background: 220 15% 12%;
  --foreground: 0 0% 95%;
  --primary: 200 80% 60%;
  --primary-foreground: 0 0% 100%;
  --secondary: 220 10% 20%;
  --secondary-foreground: 0 0% 95%;
  --muted: 220 10% 18%;
  --muted-foreground: 0 0% 65%;
  --accent: 200 60% 25%;
  --accent-foreground: 0 0% 95%;
  --card: 220 15% 15%;
  --card-foreground: 0 0% 95%;
  --card-border: 220 10% 25%;
  --border: 220 10% 25%;
  --input: 220 10% 22%;
  --ring: 200 80% 60%;
  --destructive: 0 72% 50%;
  --destructive-foreground: 0 0% 100%;
  --popover: 220 15% 16%;
  --popover-foreground: 0 0% 95%;
  --popover-border: 220 10% 25%;

  --shadow-2xs: 0px 1px 2px 0px rgba(0, 0, 0, 0.4);
  --shadow-xs: 0px 1px 3px 0px rgba(0, 0, 0, 0.5);
  --shadow-sm: 0px 2px 4px -1px rgba(0, 0, 0, 0.5);
  --shadow: 0px 4px 6px -1px rgba(0, 0, 0, 0.6);
  --shadow-md: 0px 6px 10px -2px rgba(0, 0, 0, 0.6);
  --shadow-lg: 0px 10px 15px -3px rgba(0, 0, 0, 0.7);
  --shadow-xl: 0px 20px 25px -5px rgba(0, 0, 0, 0.8);
  --shadow-2xl: 0px 25px 50px -12px rgba(0, 0, 0, 0.9);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
    font-family: var(--font-sans);
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-display);
    font-weight: 600;
    letter-spacing: -0.02em;
  }
}

@layer utilities {
  input[type="search"]::-webkit-search-cancel-button {
    @apply hidden;
  }

  [contenteditable][data-placeholder]:empty::before {
    content: attr(data-placeholder);
    color: hsl(var(--muted-foreground));
    pointer-events: none;
  }

  .no-default-hover-elevate {}
  .no-default-active-elevate {}

  .toggle-elevate::before,
  .toggle-elevate-2::before {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    border-radius: inherit;
    z-index: -1;
  }

  .toggle-elevate.toggle-elevated::before {
    background-color: var(--elevate-2);
  }

  .border.toggle-elevate::before {
    inset: -1px;
  }

  .hover-elevate:not(.no-default-hover-elevate),
  .active-elevate:not(.no-default-active-elevate),
  .hover-elevate-2:not(.no-default-hover-elevate),
  .active-elevate-2:not(.no-default-active-elevate) {
    position: relative;
    z-index: 0;
  }

  .hover-elevate:not(.no-default-hover-elevate)::after,
  .active-elevate:not(.no-default-active-elevate)::after,
  .hover-elevate-2:not(.no-default-hover-elevate)::after,
  .active-elevate-2:not(.no-default-active-elevate)::after {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    border-radius: inherit;
    z-index: 999;
  }

  .hover-elevate:hover:not(.no-default-hover-elevate)::after,
  .active-elevate:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-1);
  }

  .hover-elevate-2:hover:not(.no-default-hover-elevate)::after,
  .active-elevate-2:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-2);
  }

  .border.hover-elevate:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate-2:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate-2:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate:not(.no-hover-interaction-elevate)::after {
    inset: -1px;
  }

  /* Subtle texture overlay - minimal */
  .texture-overlay {
    position: relative;
  }

  .texture-overlay::after {
    content: "";
    position: absolute;
    inset: 0;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='2' numOctaves='2' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
    opacity: 0.03;
    pointer-events: none;
    z-index: 1;
  }

  /* Geometric panel effect */
  .geometric-panel {
    position: relative;
    border: 1px solid hsl(var(--border));
    box-shadow: var(--shadow-md);
  }

  /* Clean corner accents - minimal */
  .corner-lines::before,
  .corner-lines::after {
    content: "";
    position: absolute;
    width: 30px;
    height: 30px;
    border: 2px solid hsl(var(--primary));
    pointer-events: none;
  }

  .corner-lines::before {
    top: -1px;
    left: -1px;
    border-right: none;
    border-bottom: none;
  }

  .corner-lines::after {
    bottom: -1px;
    right: -1px;
    border-left: none;
    border-top: none;
  }

  /* Subtle lift effect */
  .lift-on-hover {
    transition: all 0.2s ease-out;
  }

  .lift-on-hover:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow-lg);
  }

  /* Hide scrollbar for horizontal scroll */
  .scrollbar-hide {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  .scrollbar-hide::-webkit-scrollbar {
    display: none;
  }

  /* Glitch Logo Animations */
  .logo-container {
    position: relative;
    display: inline-block;
  }

  .logo-image {
    display: block;
    filter: drop-shadow(0 0 8px rgba(95, 255, 175, 0.5));
  }

  /* Hero logo - animated glitch effect */
  .logo-hero .logo-image {
    animation: glitch-hero 3s infinite;
  }

  /* Nav logo - subtle glow only */
  .logo-nav .logo-image {
    transition: filter 0.3s ease;
  }

  .logo-nav:hover .logo-image {
    filter: drop-shadow(0 0 12px rgba(95, 255, 175, 0.9));
  }

  /* Glitch keyframes for hero */
  @keyframes glitch-hero {
    0%, 90%, 100% {
      transform: translate(0, 0);
      filter: drop-shadow(0 0 8px rgba(95, 255, 175, 0.5));
    }
    92% {
      transform: translate(-2px, 0);
      filter: drop-shadow(-2px 0 2px rgba(255, 0, 0, 0.5)) 
              drop-shadow(2px 0 2px rgba(0, 255, 255, 0.5));
    }
    94% {
      transform: translate(2px, 0);
      filter: drop-shadow(2px 0 2px rgba(255, 0, 0, 0.5)) 
              drop-shadow(-2px 0 2px rgba(0, 255, 255, 0.5));
    }
    96% {
      transform: translate(-1px, 0);
      filter: drop-shadow(-1px 0 2px rgba(95, 255, 175, 0.8));
    }
  }

  /* Scan line overlay */
  .glitch-scanline {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(
      transparent 50%, 
      rgba(95, 255, 175, 0.06) 50%
    );
    background-size: 100% 4px;
    pointer-events: none;
    opacity: 0.6;
  }

  .logo-hero .glitch-scanline {
    animation: scanline-scroll 8s linear infinite;
  }

  @keyframes scanline-scroll {
    0% {
      background-position: 0 0;
    }
    100% {
      background-position: 0 100%;
    }
  }

  /* Matrix-style digital background */
  .digital-matrix-bg {
    background-color: #000000;
    background-image: 
      repeating-linear-gradient(
        0deg,
        transparent,
        transparent 2px,
        rgba(95, 255, 175, 0.03) 2px,
        rgba(95, 255, 175, 0.03) 4px
      ),
      repeating-linear-gradient(
        90deg,
        transparent,
        transparent 2px,
        rgba(95, 255, 175, 0.02) 2px,
        rgba(95, 255, 175, 0.02) 4px
      );
    position: relative;
  }

  .digital-matrix-bg::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-image: 
      radial-gradient(circle, rgba(95, 255, 175, 0.04) 1px, transparent 1px);
    background-size: 20px 20px;
    opacity: 0.4;
    pointer-events: none;
  }

  /* Metallic green chrome navbar */
  .metallic-nav {
    background: linear-gradient(
      135deg,
      rgba(80, 200, 120, 0.95) 0%,
      rgba(95, 255, 175, 0.98) 25%,
      rgba(60, 180, 100, 0.96) 50%,
      rgba(95, 255, 175, 0.98) 75%,
      rgba(80, 200, 120, 0.95) 100%
    );
    box-shadow: 
      0 0 20px rgba(95, 255, 175, 0.3),
      inset 0 1px 0 rgba(255, 255, 255, 0.3),
      inset 0 -1px 0 rgba(0, 0, 0, 0.2);
    backdrop-filter: blur(12px);
    border-bottom: 2px solid rgba(95, 255, 175, 0.8);
  }

  /* Reduce motion for accessibility */
  @media (prefers-reduced-motion: reduce) {
    .logo-hero .logo-image,
    .logo-hero .glitch-scanline {
      animation: none;
    }
  }

  /* 3D Character Controller Splash Screen */
  .splash {
    position: fixed;
    inset: 0;
    background: rgba(3, 4, 5, 0.88);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 9998;
    transition: opacity 1.2s ease;
    overflow: hidden;
    cursor: pointer;
  }

  .splash::before {
    content: "";
    position: absolute;
    inset: -60% -20%;
    background: repeating-linear-gradient(
      to bottom,
      rgba(120, 255, 200, 0.12) 0,
      rgba(120, 255, 200, 0.12) 1px,
      transparent 1px,
      transparent 4px
    );
    opacity: 0.28;
    mix-blend-mode: screen;
    animation: splash-scan 1.8s linear infinite;
  }

  .splash img {
    position: absolute;
    max-width: 70vw;
    width: 480px;
    max-height: 80vh;
    object-fit: contain;
    filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35));
    mix-blend-mode: screen;
    animation: none;
    transform: scale(1);
    transition: transform 0.45s ease, filter 0.45s ease;
  }

  .splash img.splash-glitching {
    animation: splash-glitch 0.5s infinite !important;
  }

  .splash:hover img,
  .splash:focus-visible img {
    transform: scale(1.08);
    filter: drop-shadow(0 0 46px rgba(130, 255, 210, 0.55));
  }

  .splash:focus-visible {
    outline: 2px solid rgba(0, 255, 170, 0.55);
    outline-offset: 14px;
  }

  .splash img.splash-fade {
    animation: splash-fade-out 1.6s forwards !important;
  }

  @keyframes splash-scan {
    0% {
      transform: translateY(-40%);
    }
    100% {
      transform: translateY(40%);
    }
  }

  @keyframes splash-glitch {
    0%, 100% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
    2% {
      transform: translate(-8px, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1.5);
      opacity: 0.7;
    }
    4% {
      transform: translate(8px, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(0.5);
      opacity: 0.8;
    }
    6% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
    12% {
      transform: translate(-6px, 0) scaleY(0.95);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1.3);
      opacity: 0.85;
    }
    14% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
    18% {
      transform: translate(5px, 0) scaleX(1.03);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(0.8);
      opacity: 0.9;
    }
    20% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
    28% {
      transform: translate(-10px, 0) scale(1.02);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1.4);
      opacity: 0.6;
    }
    30% {
      transform: translate(4px, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(0.7);
      opacity: 0.9;
    }
    32% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
    45% {
      transform: translate(-4px, 0) scaleY(1.04);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1.2);
      opacity: 0.75;
    }
    47% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
    55% {
      transform: translate(7px, 0) scaleX(0.97);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(0.6);
      opacity: 0.8;
    }
    57% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
    68% {
      transform: translate(-5px, 0) scale(1.01);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1.6);
      opacity: 0.7;
    }
    70% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
    82% {
      transform: translate(9px, 0) scaleY(0.98);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(0.5);
      opacity: 0.85;
    }
    84% {
      transform: translate(-3px, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1.3);
      opacity: 0.9;
    }
    86% {
      transform: translate(0, 0) scale(1);
      filter: drop-shadow(0 0 32px rgba(130, 200, 255, 0.35)) brightness(1);
      opacity: 1;
    }
  }

  @keyframes splash-fade-out {
    0% {
      opacity: 1;
      transform: scale(1);
    }
    40% {
      opacity: 0.8;
      transform: scale(1.03);
    }
    70% {
      opacity: 0.3;
      transform: scale(1.06);
    }
    100% {
      opacity: 0;
      transform: scale(1.12);
    }
  }

  @media (max-width: 640px) {
    .splash img {
      width: 70vw;
    }
  }
}

