    }

    setIsLoading(true);

    try {
      await register(username, email, password);
      toast({
        title: "Account created!",
        description: "Welcome to the void",
      });
      setLocation("/");
    } catch (error) {
      toast({
        title: "Registration failed",
        description: "Username or email might already be taken",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen pt-24 pb-12 flex items-center justify-center grain-overlay">
      <div className="container mx-auto px-4 max-w-md">
        <div className="bg-card border border-border rounded-md p-8">
          <h1 
            className="text-4xl font-bold uppercase tracking-wider mb-2 text-center"
            style={{ fontFamily: "'Bebas Neue', sans-serif" }}
            data-testid="text-register-title"
          >
            Register
          </h1>
          <p className="text-sm text-muted-foreground text-center mb-8">
            Join the digital decay
          </p>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label htmlFor="username" className="block text-sm font-medium mb-2">
                Username
              </label>
              <Input
                id="username"
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                required
                data-testid="input-username"
              />
            </div>

            <div>
              <label htmlFor="email" className="block text-sm font-medium mb-2">
                Email
              </label>
              <Input
                id="email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                data-testid="input-email"
              />
            </div>

            <div>
              <label htmlFor="password" className="block text-sm font-medium mb-2">
                Password
              </label>
              <Input
                id="password"
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                minLength={6}
                data-testid="input-password"
              />
            </div>

            <div>
              <label htmlFor="confirmPassword" className="block text-sm font-medium mb-2">
                Confirm Password
              </label>
              <Input
                id="confirmPassword"
                type="password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                required
                minLength={6}
                data-testid="input-confirm-password"
              />
            </div>

            <Button
              type="submit"
              className="w-full uppercase tracking-wider"
              disabled={isLoading}
              data-testid="button-register"
            >
              {isLoading ? "Creating account..." : "Register"}
            </Button>
          </form>

          <div className="mt-6 text-center text-sm">
            <span className="text-muted-foreground">Already have an account? </span>
            <Link href="/login">
              <button className="text-primary hover:underline" data-testid="link-login">
                Login
              </button>
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

