html, body {
  margin:0;
  height:100%;
  background:transparent;
  color:#eaeaea;
  font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial;
  overflow:hidden;
}

#canvas-holder {
  position:fixed;
  inset:0;
}

.error-message {
  position:fixed;
  top:50%;
  left:50%;
  transform:translate(-50%, -50%);
  background:rgba(8,10,12,0.82);
  border:1px solid rgba(140,220,255,0.35);
  padding:18px 28px;
  border-radius:12px;
  font-size:15px;
  letter-spacing:0.02em;
  color:#def2ff;
  backdrop-filter:blur(6px);
  z-index:25;
  max-width:320px;
  text-align:center;
  box-shadow:0 12px 38px rgba(5,12,20,0.45);
  pointer-events:none;
}

#splash {
  position:fixed;
  inset:0;
  background:rgba(3,4,5,0.88);
  display:flex;
  align-items:center;
  justify-content:center;
  z-index:20;
  transition:opacity 1.2s ease;
  overflow:hidden;
  cursor:pointer;
}

body.intro-started #splash {
  cursor:default;
}

#splash::before {
  content:"";
  position:absolute;
  inset:-60% -20%;
  background:repeating-linear-gradient(
    to bottom,
    rgba(120,255,200,0.12) 0,
    rgba(120,255,200,0.12) 1px,
    transparent 1px,
    transparent 4px
  );
  opacity:0.28;
  mix-blend-mode:screen;
  animation:scan 1.8s linear infinite;
}

#splash img {
  position:absolute;
  max-width:70vw;
  width:480px;
  max-height:80vh;
  object-fit:contain;
  filter:drop-shadow(0 0 32px rgba(130,200,255,0.35));
  mix-blend-mode:screen;
  animation:none;
  transform:scale(1);
  transition:transform 0.45s ease, filter 0.45s ease;
}

body:not(.intro-started) #splash:hover img,
body:not(.intro-started) #splash:focus-visible img {
  transform:scale(1.08);
  filter:drop-shadow(0 0 46px rgba(130,255,210,0.55));
}

body.intro-started #splash img {
  animation:glitchPulse 3.4s steps(1, end) infinite;
}

#splash:focus-visible {
  outline:2px solid rgba(0,255,170,0.55);
  outline-offset:14px;
}

#splash img.splash-fade {
  animation:fadeOut 1.6s forwards;
}

body.splash-hidden #splash {
  opacity:0;
  pointer-events:none;
}

@keyframes scan {
  0% { transform:translateY(-40%); }
  100% { transform:translateY(40%); }
}

@keyframes glitchPulse {
  0%,8%   { transform:translate(0,0) scale(1); opacity:1; }
  9%      { transform:translate(-14%, 6%) scale(1.14) skewX(6deg); opacity:0.62; }
  10%     { transform:translate(12%, -5%) scale(1.11) skewX(-5deg); opacity:0.68; }
  11%     { transform:translate(0,0) scale(1.01); opacity:1; }
  18%     { transform:translate(0,0) scale(1); opacity:1; }
  19%     { transform:translate(18%, -8%) scale(1.15) skewY(4deg); opacity:0.55; }
  20%     { opacity:0; }
  22%     { transform:translate(-18%, 8%) scale(1.13) skewX(-4deg); opacity:0.66; }
  24%     { transform:translate(6%, -3%) scale(1.06); opacity:0.82; }
  26%     { transform:translate(0,0) scale(1.02); opacity:1; }
  34%     { transform:translate(0,0) scale(1); opacity:1; }
  35%     { transform:translate(-9%, -6%) scale(1.09) skewY(3deg); opacity:0.63; }
  36%     { opacity:0; }
  38%     { transform:translate(13%, 6%) scale(1.08) skewX(-3deg); opacity:0.76; }
  40%     { transform:translate(0,0) scale(1.01); opacity:1; }
  50%     { transform:translate(0,0) scale(1); opacity:1; }
  51%     { transform:translate(-6%, 3%) scale(1.05); opacity:0.88; }
  52%     { transform:translate(7%, -2%) scale(1.05); opacity:0.84; }
  53%     { opacity:0; }
  55%     { transform:translate(0,0) scale(1.02); opacity:1; }
  64%     { transform:translate(4%, -1%) scale(1.03); opacity:0.93; }
  65%     { transform:translate(-12%, 3%) scale(1.08); opacity:0.68; }
  66%     { opacity:0; }
  68%     { transform:translate(11%, -4%) scale(1.07); opacity:0.77; }
  70%     { transform:translate(0,0) scale(1.01); opacity:1; }
  80%     { transform:translate(0,0) scale(1); opacity:1; }
  81%     { transform:translate(-15%, -7%) scale(1.1); opacity:0.58; }
  82%     { transform:translate(16%, 7%) scale(1.09); opacity:0.64; }
  83%     { opacity:0; }
  86%     { transform:translate(-6%, 4%) scale(1.05); opacity:0.83; }
  100%    { transform:translate(0,0) scale(1); opacity:1; }
}

@keyframes fadeOut {
  0%   { opacity:1; transform:scale(1); }
  40%  { opacity:0.8; transform:scale(1.03); }
  70%  { opacity:0.3; transform:scale(1.06); }
  100% { opacity:0; transform:scale(1.12); }
}

@media (max-width:640px) {
  #splash img {
    width:70vw;
  }
}

