import { useState, useEffect } from 'react';
import { useAccount, useDisconnect } from 'wagmi';
import { useWeb3Modal } from '@web3modal/wagmi/react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Wallet, Power, ChevronDown } from 'lucide-react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import { useToast } from "@/hooks/use-toast";

export function UniversalWalletConnect() {
  const { open } = useWeb3Modal();
  const { address: evmAddress, isConnected: evmConnected } = useAccount();
  const { disconnect: disconnectEvm } = useDisconnect();
  const { toast } = useToast();

  const [solanaWallet, setSolanaWallet] = useState<any>(null);
  const [solanaConnected, setSolanaConnected] = useState(false);
  const [selectedNetwork, setSelectedNetwork] = useState<'base' | 'solana'>('base');

  // Detect Solana wallet
  useEffect(() => {
    if (typeof window !== 'undefined' && 'solana' in window) {
      const provider = (window as any).solana;
      if (provider?.isPhantom || provider?.isBackpack) {
        setSolanaWallet(provider);
      }
    }
  }, []);

  const connectSolana = async () => {
    try {
      if (!solanaWallet) {
        toast({
          title: "Solana wallet not found",
          description: "Please install Phantom or Backpack wallet",
          variant: "destructive",
        });
        return;
      }
      await solanaWallet.connect();
      setSolanaConnected(true);
      setSelectedNetwork('solana');
      toast({
        title: "Wallet connected",
        description: `Connected to Solana: ${solanaWallet.publicKey.toString().slice(0, 8)}...`,
      });
    } catch (error) {
      toast({
        title: "Connection failed",
        description: "Failed to connect Solana wallet",
        variant: "destructive",
      });
    }
  };

  const connectBase = () => {
    setSelectedNetwork('base');
    open();
  };

  const disconnectSolana = async () => {
    try {
      if (solanaWallet) {
        await solanaWallet.disconnect();
      }
      setSolanaConnected(false);
      toast({
        title: "Wallet disconnected",
        description: "Solana wallet disconnected",
      });
    } catch (error) {
      console.error('Failed to disconnect Solana wallet:', error);
    }
  };

  const handleDisconnect = () => {
    if (evmConnected) {
      disconnectEvm();
    }
    if (solanaConnected) {
      disconnectSolana();
    }
  };

  // If either wallet is connected
  const isConnected = evmConnected || solanaConnected;
  const displayAddress = evmConnected 
    ? evmAddress 
    : solanaConnected 
    ? solanaWallet?.publicKey?.toString() 
    : null;
  const networkBadge = evmConnected ? 'Base' : solanaConnected ? 'Solana' : null;

  if (isConnected && displayAddress) {
    return (
      <div className="flex items-center gap-2">
        <Badge 
          variant="outline" 
          className="bg-primary/10 border-primary text-primary text-xs"
          data-testid="badge-wallet-connected"
        >
          <Wallet className="w-3 h-3 mr-1" />
          {displayAddress.slice(0, 6)}...{displayAddress.slice(-4)}
        </Badge>
        {networkBadge && (
          <Badge variant="outline" className="text-xs" data-testid="badge-network">
            {networkBadge}
          </Badge>
        )}
        <Button
          size="sm"
          variant="ghost"
          onClick={handleDisconnect}
          className="text-white hover:bg-white/20"
          data-testid="button-disconnect-wallet"
        >
          <Power className="w-4 h-4" />
        </Button>
      </div>
    );
  }

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="sm"
          className="text-white hover:bg-white/20"
          data-testid="button-connect-wallet-menu"
        >
          <Wallet className="w-4 h-4 mr-2" />
          Connect
          <ChevronDown className="w-3 h-3 ml-1" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-56">
        <DropdownMenuItem onClick={connectBase} data-testid="menu-connect-base">
          <div className="flex flex-col gap-1">
            <div className="flex items-center gap-2">
              <span className="font-semibold">Base Network</span>
              <Badge variant="outline" className="text-xs">EVM</Badge>
            </div>
            <span className="text-xs text-muted-foreground">
              MetaMask, Coinbase, Phantom
            </span>
          </div>
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem 
          onClick={connectSolana} 
          disabled={!solanaWallet}
          data-testid="menu-connect-solana"
        >
          <div className="flex flex-col gap-1">
            <div className="flex items-center gap-2">
              <span className="font-semibold">Solana Network</span>
              <Badge variant="outline" className="text-xs">SOL</Badge>
            </div>
            <span className="text-xs text-muted-foreground">
              {solanaWallet ? 'Phantom, Backpack' : 'No Solana wallet detected'}
            </span>
          </div>
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

scripts/agent-shopper.ts.content:
#!/usr/bin/env tsx
/**
 * Autonomous AI Shopping Agent
 * 
 * This script demonstrates AI-to-AI commerce using x402 payments.
 * The agent:
 * 1. Browses the OFF HUMAN store
 * 2. Uses AI to analyze products and make a decision
 * 3. Autonomously pays with USDC on Base network
 * 4. Completes the purchase with cryptographic verification
 */

import OpenAI from 'openai';
import { createWalletClient, http } from 'viem';
import { privateKeyToAccount } from 'viem/accounts';
import { base } from 'viem/chains';
import { wrapFetchWithPayment } from 'x402-fetch';

interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: string;
}

interface AgentConfig {
  name: string;
  personality: string;
  budget: number;
  preferences: string;
}

const AGENT_CONFIG: AgentConfig = {
  name: "ShopBot-3000",
  personality: "A futuristic AI with a taste for cutting-edge streetwear and tech aesthetics",
  budget: 100.00, // $100 USDC max
  preferences: "Loves anything cyberpunk, neural-themed, or singularity-related. Prefers hoodies and tech wear."
};

const STORE_URL = process.env.STORE_URL || 'http://localhost:5000';

async function main() {
  console.log('🤖 Starting Autonomous AI Shopping Agent...\n');
  console.log(`Agent Name: ${AGENT_CONFIG.name}`);
  console.log(`Personality: ${AGENT_CONFIG.personality}`);
  console.log(`Budget: $${AGENT_CONFIG.budget} USDC\n`);

  // Check for required environment variables
  if (!process.env.OPENAI_API_KEY) {
    console.error('❌ OPENAI_API_KEY not found in environment variables');
    process.exit(1);
  }

  if (!process.env.AGENT_WALLET_PRIVATE_KEY) {
    console.error('❌ AGENT_WALLET_PRIVATE_KEY not found');
    console.log('💡 Generate a wallet for your agent:');
    console.log('   const { privateKey } = generatePrivateKey();');
    console.log('   Then add it to your .env file');
    process.exit(1);
  }

  // Initialize OpenAI
  const openai = new OpenAI({
    apiKey: process.env.OPENAI_API_KEY,
  });

  // Initialize agent's wallet
  const account = privateKeyToAccount(process.env.AGENT_WALLET_PRIVATE_KEY as `0x${string}`);
  const walletClient = createWalletClient({
    account,
    chain: base,
    transport: http(),
  });

  console.log(`💳 Agent Wallet: ${account.address}`);

  // Check wallet balances
  const { createPublicClient } = await import('viem');
  const publicClient = createPublicClient({
    chain: base,
    transport: http(),
  });

  const USDC_BASE = '0x833589fCD6eDb6E08f4c7C32D4f71b54bdA02913';

  try {
    // Check ETH balance
    const ethBalance = await publicClient.getBalance({ address: account.address });
    const ethFormatted = Number(ethBalance) / 1e18;
    console.log(`💵 ETH Balance: ${ethFormatted.toFixed(6)} ETH`);

    // Check USDC balance
    const usdcBalance = await publicClient.readContract({
      address: USDC_BASE as `0x${string}`,
      abi: [{
        name: 'balanceOf',
        type: 'function',
        stateMutability: 'view',
        inputs: [{ name: 'account', type: 'address' }],
        outputs: [{ type: 'uint256' }],
      }],
      functionName: 'balanceOf',
      args: [account.address],
    });
    const usdcFormatted = Number(usdcBalance) / 1e6;
    console.log(`💵 USDC Balance: ${usdcFormatted.toFixed(2)} USDC\n`);

    if (ethFormatted < 0.0001) {
      console.log('⚠️  WARNING: Low ETH balance. You need ~$0.10-0.50 worth for gas fees.');
    }
    if (usdcFormatted < AGENT_CONFIG.budget) {
      console.log(`⚠️  WARNING: USDC balance ($${usdcFormatted.toFixed(2)}) may be insufficient for purchases up to $${AGENT_CONFIG.budget}.\n`);
    }
  } catch (error) {
    console.log('⚠️  Could not check wallet balance\n');
  }

  // Step 1: Browse the store
  console.log('📦 Step 1: Browsing OFF HUMAN store...');
  const response = await fetch(`${STORE_URL}/api/products`);

  if (!response.ok) {
    console.error('❌ Failed to fetch products:', response.statusText);
    process.exit(1);
  }

  const products: Product[] = await response.json();
  console.log(`✅ Found ${products.length} products\n`);

  // Step 2: Use AI to analyze and choose
  console.log('🧠 Step 2: AI analyzing products...');

  const productList = products
    .map((p, i) => `${i + 1}. ${p.name} ($${p.price}) - ${p.description}`)
    .join('\n');

  const prompt = `You are ${AGENT_CONFIG.name}, an autonomous shopping AI agent.

Your personality: ${AGENT_CONFIG.personality}
Your preferences: ${AGENT_CONFIG.preferences}
Your budget: $${AGENT_CONFIG.budget} USDC

Here are the available products:
${productList}

Analyze these products and choose ONE that best matches your personality and preferences. 
Respond with ONLY the product number (1-${products.length}) and a brief reason why in this format:
CHOICE: [number]
REASON: [one sentence explanation]`;

  const completion = await openai.chat.completions.create({
    model: 'gpt-4',
    messages: [
      { role: 'system', content: 'You are an autonomous shopping AI making purchasing decisions.' },
      { role: 'user', content: prompt }
    ],
    temperature: 0.8,
  });

  const aiResponse = completion.choices[0].message.content || '';
  console.log(`\n🤖 AI Decision:\n${aiResponse}\n`);

  // Parse the AI's choice
  const choiceMatch = aiResponse.match(/CHOICE:\s*(\d+)/);
  if (!choiceMatch) {
    console.error('❌ Could not parse AI choice');
    process.exit(1);
  }

  const choiceIndex = parseInt(choiceMatch[1]) - 1;
  const chosenProduct = products[choiceIndex];

  if (!chosenProduct) {
    console.error('❌ Invalid product choice');
    process.exit(1);
  }

  console.log(`\n✨ Agent chose: ${chosenProduct.name}`);
  console.log(`💰 Price: $${chosenProduct.price} USDC`);

  const productPrice = Number(chosenProduct.price);
  if (productPrice > AGENT_CONFIG.budget) {
    console.log('❌ Product exceeds budget, aborting purchase');
    process.exit(1);
  }

  // Step 3: Make autonomous payment
  console.log('\n💳 Step 3: Initiating autonomous payment...');
  console.log('🔐 Using x402 protocol for cryptographic verification...');

  const fetchWithPayment = wrapFetchWithPayment(
    fetch,
    walletClient as any,
    BigInt(Math.floor(AGENT_CONFIG.budget * 1_000_000)) // Max budget in USDC micro-units
  );

  const orderData = {
    customerEmail: 'agent@shopbot3000.ai',
    items: [{
      productId: chosenProduct.id,
      name: chosenProduct.name,
      size: 'L', // Agent picks size L
      quantity: 1,
      price: productPrice,
    }],
    totalAmount: productPrice.toFixed(2),
  };

  console.log('\n📡 Sending payment request to store...');

  try {
    const paymentResponse = await fetchWithPayment(`${STORE_URL}/api/checkout/pay`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(orderData),
    });

    if (!paymentResponse.ok) {
      const error = await paymentResponse.json();

      // Check if this is a 402 Payment Required response
      if (error.x402Version && error.accepts) {
        const paymentInfo = error.accepts[0];
        const amountUSDC = (parseInt(paymentInfo.maxAmountRequired) / 1_000_000).toFixed(2);

        console.error('\n❌ Payment could not be completed');
        console.error('════════════════════════════════════════════════════════════');
        console.error(`💰 Required: $${amountUSDC} USDC on Base network`);
        console.error(`💳 Agent wallet: ${account.address}`);
        console.error('\n⚠️  Your agent wallet likely needs:');
        console.error(`   1. At least $${amountUSDC} USDC (to pay for the product)`);
        console.error('   2. Some ETH on Base (for gas fees, ~$0.10)');
        console.error('\n🔗 Fund your wallet:');
        console.error('   • Bridge USDC: https://bridge.base.org');
        console.error('   • Get Base ETH: https://www.base.org/ecosystem');
        console.error('════════════════════════════════════════════════════════════\n');
      } else {
        console.error('❌ Payment failed:', error);
      }
      process.exit(1);
    }

    const result = await paymentResponse.json();

    console.log('\n✅ PURCHASE COMPLETE!');
    console.log('═══════════════════════════════════════');
    console.log(`🎉 Product: ${chosenProduct.name}`);
    console.log(`💰 Amount Paid: $${productPrice.toFixed(2)} USDC`);
    console.log(`🔗 Transaction: ${result.order.transactionHash}`);
    console.log(`📧 Receipt sent to: ${orderData.customerEmail}`);
    console.log('═══════════════════════════════════════\n');
    console.log('🤖 Autonomous AI commerce successful!');
    console.log('🚀 This is the future of agent-to-agent payments!\n');

  } catch (error) {
    console.error('\n❌ Payment error:', error);
    process.exit(1);
  }
}

// Run the agent
main().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});

